const input = $json || {};
const parsedInvoice = input.parsed_invoice || input.parsedInvoice;
if (!parsedInvoice || !Array.isArray(parsedInvoice.items)) throw new Error('parsed_invoice.items is required');

const zalo_user_id = String(input.zalo_user_id || '').trim();
const zalo_msg_id = String(input.zalo_msg_id || '').trim();
if (!zalo_user_id || !zalo_msg_id) throw new Error('zalo_user_id and zalo_msg_id are required');

const supplierCode = String(parsedInvoice.supplier_code || input.supplier_code || 'UNKNOWN_SUPPLIER');
const quote = (v) => "'" + String(v).replace(/'/g, "''") + "'";

const barcodeValues = [...new Set(parsedInvoice.items.map(i => i.barcode).filter(Boolean).map(String))];
const itemCodes = [...new Set(parsedInvoice.items.map(i => i.supplier_item_code).filter(Boolean).map(String))];

let whereParts = [];
if (barcodeValues.length) whereParts.push(`barcode IN (${barcodeValues.map(quote).join(',')})`);
if (itemCodes.length) whereParts.push(`(supplier_code = ${quote(supplierCode)} AND supplier_item_code IN (${itemCodes.map(quote).join(',')}))`);
if (!whereParts.length) whereParts.push('1=0');

const lookupQuery = `SELECT id, supplier_code, supplier_item_code, barcode, supplier_unit, pos_unit, conversion_rate, kiotviet_product_id, kiotviet_product_code, kiotviet_product_name FROM mapping_dictionary WHERE is_active = TRUE AND (${whereParts.join(' OR ')})`;

return [{ json: { ...input, parsed_invoice: parsedInvoice, zalo_user_id, zalo_msg_id, supplier_code: supplierCode, lookup_query: lookupQuery, started_at: Date.now() } }];

const ctx = $('Validate + Build Lookup Query').item.json;
const mappings = $input.all().map(i => i.json);
const parsedInvoice = ctx.parsed_invoice;

const byBarcode = new Map();
const bySupplierCode = new Map();
for (const m of mappings) {
  if (m.barcode) byBarcode.set(String(m.barcode), m);
  const key = `${m.supplier_code || ''}::${m.supplier_item_code || ''}`;
  bySupplierCode.set(key, m);
}

const warnings = [];
const mapped_items = [];
const unmapped_items = [];

for (const item of parsedInvoice.items) {
  let mapping = null;
  if (item.barcode && byBarcode.has(String(item.barcode))) {
    mapping = byBarcode.get(String(item.barcode));
  } else {
    const key = `${ctx.supplier_code}::${item.supplier_item_code || ''}`;
    mapping = bySupplierCode.get(key) || null;
  }

  if (!mapping) {
    unmapped_items.push(item);
    continue;
  }

  let rate = Number(mapping.conversion_rate || 1);
  if (!Number.isFinite(rate) || rate <= 0) {
    warnings.push(`Invalid conversion_rate for ${item.supplier_item_code}; fallback to 1`);
    rate = 1;
  }

  const quantity = Number(item.quantity || 0);
  const unitPrice = Number(item.unit_price || 0);
  const converted_qty = quantity * rate;
  const converted_unit_price = item.is_promotion ? 0 : unitPrice / rate;

  mapped_items.push({
    ...item,
    mapping_id: mapping.id,
    kiotviet_product_id: mapping.kiotviet_product_id,
    kiotviet_product_code: mapping.kiotviet_product_code,
    kiotviet_product_name: mapping.kiotviet_product_name,
    supplier_unit: mapping.supplier_unit,
    pos_unit: mapping.pos_unit,
    conversion_rate: rate,
    converted_qty,
    converted_unit_price,
    total_before: quantity * unitPrice,
    total_after: converted_qty * converted_unit_price
  });
}

return [{ json: { ...ctx, mapped_items, unmapped_items, warnings } }];

return [{ json: {
  status: 'needs_mapping',
  zalo_user_id: $json.zalo_user_id,
  zalo_msg_id: $json.zalo_msg_id,
  unmapped_items: $json.unmapped_items,
  mapped_so_far: $json.mapped_items,
  warnings: $json.warnings
}}];

const ctx = $json;
const details = ctx.mapped_items.map((m) => ({
  productId: m.kiotviet_product_id,
  productCode: m.kiotviet_product_code,
  quantity: m.converted_qty,
  price: m.is_promotion ? 0 : m.converted_unit_price,
  discount: 0,
  description: m.is_promotion ? 'KM - Hàng tặng (Promo)' : ''
}));

const totalPayment = details.reduce((sum, d) => sum + (Number(d.quantity) * Number(d.price)), 0);
const invoiceRef = ctx.parsed_invoice.invoice_number || ctx.zalo_msg_id;
const poPayload = {
  branchId: Number($env.KIOTVIET_BRANCH_ID || 1),
  supplierId: Number($env.KIOTVIET_SUPPLIER_ID || 0),
  supplierCode: String($env.KIOTVIET_SUPPLIER_CODE || `NCC_${ctx.supplier_code}`),
  purchaseOrderDetails: details,
  status: 2,
  statusValue: 'Hoàn thành',
  totalPayment,
  description: `Auto-import via KiotViet-Taphoa Bot | Bill: ${invoiceRef} | Source: XML`,
  payments: [{ Method: 'Cash', Amount: totalPayment, AccountId: null }]
};

return [{ json: { ...ctx, po_payload: poPayload } }];

const poResp = $json || {};
const ctx = $('Build PO Payload').item.json;
const poId = poResp.id || poResp.data?.id || null;
const poCode = poResp.code || poResp.data?.code || null;
const processing_time_ms = Math.max(0, Date.now() - Number(ctx.started_at || Date.now()));
return [{ json: { ...ctx, kiotviet_po_id: poId, kiotviet_po_code: poCode, processing_time_ms } }];

return [{ json: {
  status: 'completed',
  zalo_user_id: $json.zalo_user_id,
  zalo_msg_id: $json.zalo_msg_id,
  kiotviet_po_id: $json.kiotviet_po_id,
  kiotviet_po_code: $json.kiotviet_po_code,
  mapped_items: $json.mapped_items,
  warnings: $json.warnings
}}];
